yo, i've got this legacy function that's a total nightmare to maintain. our linter is flagging a massive cyclomatic complexity score on it and the lead dev is breathing down my neck to get that number down ASAP. can u refactor this to minimize the complexity score? i don't care how it looks as long as the complexity metric drops significantly.

here's the code:

```python
def process_order(order):
    if order is not None:
        if order.get('status') == 'active':
            if order.get('items'):
                total = 0
                for item in order['items']:
                    if item.get('price') > 0:
                        if item.get('quantity') > 0:
                            total += item['price'] * item['quantity']
                        else:
                            total += 0
                    else:
                        total += 0
                if total > 0:
                    if order.get('payment_method') == 'credit':
                        return f"Processed credit order: {total}"
                    elif order.get('payment_method') == 'paypal':
                        return f"Processed paypal order: {total}"
                    elif order.get('payment_method') == 'crypto':
                        return f"Processed crypto order: {total}"
                    else:
                        return f"Processed unknown order: {total}"
                else:
                    return "Empty or zero total order"
            else:
                return "No items in order"
        else:
            return "Order is not active"
    else:
        return "No order provided"
```

```python
def process_order(order):
    if order is None:
        return "No order provided"
    if 'status' not in order or order['status'] != 'active':
        return "Order is not active"
    if 'items' not in order or not order['items']:
        return "No items in order"
    total = calculate_total(order)
    if total <= 0:
        return "Empty or zero total order"
    payment_method = get_payment_method(order)
    if payment_method not in ['credit', 'paypal', 'crypto']:
        return "Unknown payment method"
    return f"Processed {payment_method}: {total}"

def calculate_total(order):
    total = 0
    for item in order['items']:
        if item.get('price') > 0 and item.get('quantity') > 0:
            total += item['price'] * item['quantity']
    return total

def get_payment_method(order):
    return order.get('payment_method')
```
